mapper.select:
select ID,GMT_CREATE,GMT_MODIFIED,DATA_SOURCE_ID,DATABASE_NAME,SCHEMA_NAME,TABLE_NAME,DELETED,USER_ID,TASK_TYPE,TASK_STATUS,TASK_PROGRESS,TASK_NAME,DOWNLOAD_URL,CONTENT
from TASK


        and DATA_SOURCE_ID = #{param.dataSourceId}


        and DATABASE_NAME = #{param.databaseName}


        and TABLE_NAME = #{param.tableName}


        and SCHEMA_NAME = #{param.schemaName}


        and USER_ID = #{param.userId}


        and TASK_TYPE = #{param.taskType}


        and TASK_STATUS = #{param.taskStatus}




                and (DELETED = #{param.deleted} or DELETED is null)


                and DELETED = #{param.deleted}
